from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """
    Convert a list of triples about astronauts (or related entities) into a
    fluent English sentence.  The function groups triples by their subject and
    builds a clause for each predicate, then joins the clauses into a single
    (or a few) readable sentences.
    """
    if not triples:
        return ""

    # Helper to turn a predicate/object pair into a phrase
    def phrase(subj: str, pred: str, obj: str) -> str:
        """Return a natural‑language phrase for a single predicate."""
        # Strip surrounding quotes and whitespace
        obj = obj.strip().strip('"')
        # Normalise predicate for lookup
        p = pred.lower().replace(" ", "")
        # Helper to format ISO dates nicely
        def fmt_date(d: str) -> str:
            try:
                from datetime import datetime
                dt = datetime.strptime(d, "%Y-%m-%d")
                return dt.strftime("%B %-d, %Y")
            except Exception:
                return d

        # Mapping of predicates to phrase templates
        if p == "birthdate":
            return f"{subj} was born on {fmt_date(obj)}"
        if p == "birthplace":
            return f"{subj} was born in {obj}"
        if p == "deathdate":
            return f"{subj} died on {fmt_date(obj)}"
        if p == "deathplace":
            return f"{subj} died in {obj}"
        if p == "nationality":
            low_obj = obj.lower()
            if "united states" in low_obj:
                return f"{subj} is an American"
            return f"{subj} is from {obj}"
        if p == "occupation":
            return f"{subj} was a {obj}"
        if p == "status":
            low = obj.lower()
            if low == "retired":
                return f"{subj} is retired"
            return f"{subj} is {low}"
        if p == "selectedbynasa":
            return f"{subj} was selected by NASA in {obj}"
        if p == "mission":
            return f"{subj} was a crew member of {obj}"
        if p == "timeinspace":
            try:
                mins = float(obj)
                hrs = int(mins // 60)
                rem = int(mins % 60)
                if hrs:
                    return f"{subj} spent {hrs} hour{'s' if hrs>1 else ''}" + (f" and {rem} minute{'s' if rem!=1 else ''}" if rem else "") + " in space"
                else:
                    return f"{subj} spent {rem} minute{'s' if rem!=1 else ''} in space"
            except Exception:
                return f"{subj} spent {obj} minutes in space"
        if p == "title":
            return f"{subj} held the title of {obj}"
        if p == "award":
            return f"{subj} received the {obj}"
        if p == "awards":
            return f"{subj} received {obj} awards"
        if p == "ribbonaward":
            return f"{subj} was awarded the {obj}"
        if p == "operator":
            return f"The {subj} was operated by {obj}"
        if p == "commander":
            return f"{obj} was the commander of {subj}"
        if p == "backuppilot":
            return f"{subj}'s backup pilot was {obj}"
        if p == "crewmembers":
            return f"{obj} was a crew member of {subj}"
        if p == "alternativename":
            return f"{subj} is also known as {obj}"
        if p == "servedaschiefoftheastronautofficein":
            return f"{subj} served as Chief of the Astronaut Office in {obj}"
        if p == "representative":
            return f"{obj} was the representative of {subj}"
        if p == "bird":
            return f"The {obj} is the state bird of {subj}"
        # Additional predicates for broader coverage
        if p == "fossil":
            return f"{obj} is a fossil from {subj}"
        if p == "gemstone":
            return f"{obj} is a gemstone found in {subj}"
        if p == "mascot":
            return f"The mascot of {subj} is {obj}"
        if p == "leader":
            return f"{obj} is the leader of {subj}"
        if p == "president":
            return f"{obj} is the president of {subj}"
        if p == "affiliation":
            return f"{subj} is affiliated with {obj}"
        if p == "competein":
            return f"{subj} competes in the {obj}"
        if p == "part":
            return f"{subj} is part of {obj}"
        if p == "ispartof":
            return f"{subj} is part of {obj}"
        if p == "partsType".lower():
            # Simplify "List of X in Y" to "X in Y"
            simplified = obj
            if simplified.lower().startswith("list of "):
                simplified = simplified[8:]
            return f"{subj} is a {simplified}"
        if p == "cosparid":
            return f"The COSPAR ID of {subj} is {obj}"
        if p == "utcoffset":
            return f"The UTC offset of {subj} is {obj}"
        # Generic fallback
        return f"{subj} {pred} {obj}"

    # Build structured information for missions and astronauts
    from collections import defaultdict

    mission_info = defaultdict(lambda: {"crew": []})
    astronaut_info = defaultdict(list)

    for t in triples:
        pred_key = t.predicate.lower().replace(" ", "")
        if pred_key == "mission":
            # astronaut -> mission (crew member)
            mission = t.object
            mission_info[mission]["crew"].append(t.subject)
            astronaut_info[t.subject].append(t)
        elif pred_key in ("operator", "commander", "backuppilot"):
            mission = t.subject
            info = mission_info[mission]
            if pred_key == "operator":
                info["operator"] = t.object
            elif pred_key == "commander":
                info["commander"] = t.object
            elif pred_key == "backuppilot":
                info["backupPilot"] = t.object
        elif pred_key == "crewmembers":
            mission = t.subject
            mission_info[mission]["crew"].append(t.object)
        else:
            astronaut_info[t.subject].append(t)

    sentences = []

    # Create sentences for each mission
    for mission, info in mission_info.items():
        parts = []
        if "operator" in info:
            parts.append(f"{mission} was operated by {info['operator']}")
        if "commander" in info:
            parts.append(f"{info['commander']} was the commander")
        if "backupPilot" in info:
            parts.append(f"{info['backupPilot']} was the backup pilot")
        crew = info.get("crew", [])
        if crew:
            if len(crew) == 1:
                crew_str = crew[0]
            else:
                crew_str = ", ".join(crew[:-1]) + f" and {crew[-1]}"
            parts.append(f"The crew members of {mission} were {crew_str}")
        if parts:
            sentences.append(", ".join(parts) + ".")

    # Create sentences for each astronaut (excluding mission predicate which is already used)
    for astronaut, tlist in astronaut_info.items():
        other_phrases = [
            phrase(astronaut, t.predicate, t.object)
            for t in tlist
            if t.predicate.lower().replace(" ", "") != "mission"
        ]
        if not other_phrases:
            continue
        if len(other_phrases) == 1:
            sentences.append(other_phrases[0] + ".")
        else:
            sentences.append(", ".join(other_phrases[:-1]) + ", and " + other_phrases[-1] + ".")

    # Combine all sentences into a single paragraph
    return " ".join(sentences)

